# pagerduty_escalation_policy.py — create tiered escalation policy
def create_escalation_policy(
    name: str,
    sre_schedule_id: str,
    feature_schedule_id: str,
    manager_user_id: str,
    ack_timeout_minutes_tier1: int = 5,
    ack_timeout_minutes_tier2: int = 10,
) -> dict:
    payload = {
        "escalation_policy": {
            "type": "escalation_policy",
            "name": name,
            "escalation_rules": [
                {
                    "escalation_delay_in_minutes": ack_timeout_minutes_tier1,
                    "targets": [
                        {"type": "schedule_reference", "id": sre_schedule_id}
                    ],
                },
                {
                    "escalation_delay_in_minutes": ack_timeout_minutes_tier2,
                    "targets": [
                        {"type": "schedule_reference", "id": feature_schedule_id}
                    ],
                },
                {
                    "escalation_delay_in_minutes": 10,  # another 10 min for manager
                    "targets": [
                        {"type": "user_reference", "id": manager_user_id}
                    ],
                },
            ],
        }
    }
    resp = requests.post(
        "https://api.pagerduty.com/escalation_policies",
        headers=HEADERS,
        json=payload,
    )
    resp.raise_for_status()
    return resp.json()["escalation_policy"]
